export * from './resizable.component';
export * from './resizable-panel.component';
export * from './resizable-handle.component';
export * from './resizable.token';
export * from './resizable.variants';
export * from './resizable.imports';

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorDotsSixVertical } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_RESIZABLE_GROUP } from './resizable.token';
import { resizableGripVariants, resizableHandleVariants } from './resizable.variants';

@Component({
  selector: 'hb-resizable-handle, [hb-resizable-handle]',
  imports: [NgIcon],
  viewProviders: [provideIcons({ phosphorDotsSixVertical })],
  template: `
    @if (hbWithHandle()) {
      <div [class]="gripClasses()"><ng-icon name="phosphorDotsSixVertical" /></div>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'separator',
    '[class]': 'classes()',
    '[attr.data-slot]': "'resizable-handle'",
    '[attr.data-orientation]': 'orientation()',
    '[attr.aria-orientation]': 'orientation() === "vertical" ? "horizontal" : "vertical"',
    '[attr.tabindex]': 'hbDisabled() ? null : 0',
    '[attr.aria-disabled]': 'hbDisabled() || null',
    '(pointerdown)': 'onPointerDown($event)',
    '(keydown)': 'onKeydown($event)',
  },
  exportAs: 'hbResizableHandle',
})
export class HbResizableHandleComponent {
  readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly group = inject(HB_RESIZABLE_GROUP, { optional: true });

  readonly hbWithHandle = input(false, { transform: booleanAttribute });
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  protected readonly orientation = computed(() => this.group?.hbOrientation() ?? 'horizontal');
  protected readonly classes = computed(() =>
    cn(
      resizableHandleVariants({ orientation: this.orientation(), disabled: this.hbDisabled() }),
      this.class(),
    ),
  );
  protected readonly gripClasses = computed(() =>
    resizableGripVariants({ orientation: this.orientation() }),
  );

  onPointerDown(event: PointerEvent): void {
    if (this.hbDisabled() || !this.group) return;
    event.preventDefault();
    this.group.startResize(this.group.handleIndexOf(this), event);
  }

  onKeydown(event: KeyboardEvent): void {
    if (this.hbDisabled() || !this.group) return;
    const index = this.group.handleIndexOf(this);
    const horizontal = this.orientation() === 'horizontal';
    const decKey = horizontal ? 'ArrowLeft' : 'ArrowUp';
    const incKey = horizontal ? 'ArrowRight' : 'ArrowDown';
    let handled = true;
    switch (event.key) {
      case decKey:
        this.group.resizeByKeyboard(index, -1);
        break;
      case incKey:
        this.group.resizeByKeyboard(index, 1);
        break;
      case 'Home':
        this.group.resizeByKeyboard(index, 0, 'min');
        break;
      case 'End':
        this.group.resizeByKeyboard(index, 0, 'max');
        break;
      default:
        handled = false;
    }
    if (handled) event.preventDefault();
  }
}

import {
  booleanAttribute,
  computed,
  Directive,
  ElementRef,
  inject,
  input,
  numberAttribute,
  signal,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { resizablePanelVariants } from './resizable.variants';

@Directive({
  selector: 'hb-resizable-panel, [hb-resizable-panel]',
  host: {
    '[class]': 'classes()',
    '[style.flex-grow]': 'size()',
    '[style.flex-shrink]': '1',
    '[style.flex-basis]': "'0%'",
    '[attr.data-slot]': "'resizable-panel'",
    '[attr.data-collapsed]': 'isCollapsed()',
  },
  exportAs: 'hbResizablePanel',
})
export class HbResizablePanelComponent {
  readonly el = inject<ElementRef<HTMLElement>>(ElementRef);

  readonly hbDefaultSize = input<number | string | undefined>(undefined);
  readonly hbMin = input(0, { transform: numberAttribute });
  readonly hbMax = input(100, { transform: numberAttribute });
  readonly hbCollapsible = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  readonly size = signal(0);
  setSize(value: number): void {
    this.size.set(value);
  }

  protected readonly isCollapsed = computed(() => this.size() <= 0.5);
  protected readonly classes = computed(() => cn(resizablePanelVariants(), this.class()));
}

import { DOCUMENT } from '@angular/common';
import {
  type AfterContentInit,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChildren,
  DestroyRef,
  ElementRef,
  inject,
  input,
  numberAttribute,
  output,
  type OutputEmitterRef,
  signal,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbResizableHandleComponent } from './resizable-handle.component';
import { HbResizablePanelComponent } from './resizable-panel.component';
import {
  HB_RESIZABLE_GROUP,
  type HbResizableContext,
  type HbResizableHandleRef,
} from './resizable.token';
import { resizableGroupVariants, type HbResizableOrientation } from './resizable.variants';


const clamp = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max);
export interface HbResizeEvent {
  sizes: number[];
  orientation: HbResizableOrientation;
}

@Component({
  selector: 'hb-resizable-group, [hb-resizable-group]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [{ provide: HB_RESIZABLE_GROUP, useExisting: HbResizableGroupComponent }],
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'resizable-group'",
    '[attr.data-orientation]': 'hbOrientation()',
  },
  exportAs: 'hbResizableGroup',
})
export class HbResizableGroupComponent implements AfterContentInit, HbResizableContext {
  private readonly document = inject(DOCUMENT);
  private readonly destroyRef = inject(DestroyRef);
  private readonly host = inject<ElementRef<HTMLElement>>(ElementRef);

  readonly hbOrientation = input<HbResizableOrientation>('horizontal');
  readonly hbKeyboardStep = input(5, { transform: numberAttribute });
  readonly class = input<ClassValue>('');

  readonly hbResizeStart = output<HbResizeEvent>();
  readonly hbResize = output<HbResizeEvent>();
  readonly hbResizeEnd = output<HbResizeEvent>();

  readonly panels = contentChildren(HbResizablePanelComponent);
  readonly handles = contentChildren(HbResizableHandleComponent);
  readonly panelSizes = signal<number[]>([]);

  protected readonly classes = computed(() =>
    cn(resizableGroupVariants({ orientation: this.hbOrientation() }), this.class()),
  );

  private moveCleanup: (() => void) | null = null;

  constructor() {
    this.destroyRef.onDestroy(() => this.stopTracking());
  }

  ngAfterContentInit(): void {
    this.initSizes();
  }

  handleIndexOf(handle: HbResizableHandleRef): number {
    return this.handles().indexOf(handle as HbResizableHandleComponent);
  }

  startResize(handleIndex: number, event: PointerEvent): void {
    const panels = this.panels();
    const leftIdx = handleIndex;
    const rightIdx = handleIndex + 1;
    if (leftIdx < 0 || rightIdx >= panels.length) return;

    const horizontal = this.hbOrientation() === 'horizontal';
    const container = this.containerSize();
    const startPos = horizontal ? event.clientX : event.clientY;
    const sizes = [...this.panelSizes()];
    const leftStart = sizes[leftIdx];
    const rightStart = sizes[rightIdx];
    const [leftMin, leftMax] = this.limits(panels[leftIdx]);
    const [rightMin, rightMax] = this.limits(panels[rightIdx]);

    this.emit(this.hbResizeStart);
    this.document.body.style.userSelect = 'none';
    this.document.body.style.cursor = horizontal ? 'col-resize' : 'row-resize';

    const onMove = (e: PointerEvent): void => {
      const pos = horizontal ? e.clientX : e.clientY;
      const deltaPct = ((pos - startPos) / container) * 100;
      this.redistribute(leftIdx, rightIdx, leftStart, rightStart, deltaPct, [
        leftMin,
        leftMax,
        rightMin,
        rightMax,
      ]);
      this.emit(this.hbResize);
    };
    const onUp = (): void => {
      this.stopTracking();
      this.document.body.style.userSelect = '';
      this.document.body.style.cursor = '';
      this.emit(this.hbResizeEnd);
    };
    this.document.addEventListener('pointermove', onMove);
    this.document.addEventListener('pointerup', onUp);
    this.moveCleanup = () => {
      this.document.removeEventListener('pointermove', onMove);
      this.document.removeEventListener('pointerup', onUp);
    };
  }

  resizeByKeyboard(
    handleIndex: number,
    direction: number,
    toExtreme: 'min' | 'max' | null = null,
  ): void {
    const panels = this.panels();
    const leftIdx = handleIndex;
    const rightIdx = handleIndex + 1;
    if (leftIdx < 0 || rightIdx >= panels.length) return;

    const sizes = this.panelSizes();
    const leftStart = sizes[leftIdx];
    const rightStart = sizes[rightIdx];
    const [leftMin, leftMax] = this.limits(panels[leftIdx]);
    const [rightMin, rightMax] = this.limits(panels[rightIdx]);

    let deltaPct: number;
    if (toExtreme === 'min') deltaPct = leftMin - leftStart;
    else if (toExtreme === 'max') deltaPct = leftMax - leftStart;
    else deltaPct = direction * this.hbKeyboardStep();

    this.redistribute(leftIdx, rightIdx, leftStart, rightStart, deltaPct, [
      leftMin,
      leftMax,
      rightMin,
      rightMax,
    ]);
    this.emit(this.hbResize);
    this.emit(this.hbResizeEnd);
  }

  private redistribute(
    leftIdx: number,
    rightIdx: number,
    leftStart: number,
    rightStart: number,
    deltaPct: number,
    [leftMin, leftMax, rightMin, rightMax]: number[],
  ): void {
    let newLeft = clamp(leftStart + deltaPct, leftMin, leftMax);
    let newRight = rightStart - (newLeft - leftStart);
    const clampedRight = clamp(newRight, rightMin, rightMax);
    if (clampedRight !== newRight) {
      newLeft = leftStart + (rightStart - clampedRight);
      newRight = clampedRight;
    }
    const next = [...this.panelSizes()];
    next[leftIdx] = newLeft;
    next[rightIdx] = newRight;
    this.applySizes(next);
  }

  private limits(panel: HbResizablePanelComponent): [number, number] {
    return [panel.hbCollapsible() ? 0 : panel.hbMin(), panel.hbMax()];
  }

  private initSizes(): void {
    const panels = this.panels();
    if (!panels.length) return;

    const resolved = panels.map((p) => {
      const d = p.hbDefaultSize();
      if (d === undefined || d === null || d === '') return null;
      const num = typeof d === 'number' ? d : Number.parseFloat(String(d));
      return Number.isFinite(num) ? num : null;
    });
    const sumDefined = resolved.reduce<number>((acc, v) => acc + (v ?? 0), 0);
    const undefinedCount = resolved.filter((v) => v === null).length;
    const share = undefinedCount > 0 ? Math.max(0, 100 - sumDefined) / undefinedCount : 0;

    let sizes = resolved.map((v) => (v === null ? share : v));
    const total = sizes.reduce((a, b) => a + b, 0) || 1;
    sizes = sizes.map((s) => (s / total) * 100);
    this.applySizes(sizes);
  }

  private applySizes(sizes: number[]): void {
    this.panelSizes.set(sizes);
    this.panels().forEach((panel, i) => panel.setSize(sizes[i] ?? 0));
  }

  private containerSize(): number {
    const el = this.host.nativeElement;
    const horizontal = this.hbOrientation() === 'horizontal';
    const full = horizontal ? el.offsetWidth : el.offsetHeight;
    const handlesPx = this.handles().reduce((sum, h) => {
      const he = h.el.nativeElement;
      return sum + (horizontal ? he.offsetWidth : he.offsetHeight);
    }, 0);
    return Math.max(1, full - handlesPx);
  }

  private stopTracking(): void {
    this.moveCleanup?.();
    this.moveCleanup = null;
  }

  private emit(out: OutputEmitterRef<HbResizeEvent>): void {
    out.emit({
      sizes: this.panelSizes().map((s) => Math.round(s * 100) / 100),
      orientation: this.hbOrientation(),
    });
  }
}

import { HbResizableGroupComponent } from './resizable.component';
import { HbResizableHandleComponent } from './resizable-handle.component';
import { HbResizablePanelComponent } from './resizable-panel.component';

export const HbResizableImports = [
  HbResizableGroupComponent,
  HbResizablePanelComponent,
  HbResizableHandleComponent,
] as const;

import { type ElementRef, InjectionToken } from '@angular/core';

import { type HbResizableOrientation } from './resizable.variants';

export interface HbResizableHandleRef {
  readonly el: ElementRef<HTMLElement>;
}

export interface HbResizableContext {
  hbOrientation: () => HbResizableOrientation;
  startResize(handleIndex: number, event: PointerEvent): void;
  handleIndexOf(handle: HbResizableHandleRef): number;
  resizeByKeyboard(handleIndex: number, direction: number, toExtreme?: 'min' | 'max' | null): void;
}

export const HB_RESIZABLE_GROUP = new InjectionToken<HbResizableContext>('HB_RESIZABLE_GROUP');

import { cva, type VariantProps } from 'class-variance-authority';

export const resizableGroupVariants = cva('flex', {
  variants: {
    orientation: { horizontal: 'w-full flex-row', vertical: 'h-full flex-col' },
  },
  defaultVariants: { orientation: 'horizontal' },
});

export const resizableHandleVariants = cva(
  'relative flex shrink-0 items-center justify-center bg-border outline-none focus-visible:ring-1 focus-visible:ring-ring focus-visible:ring-offset-1',
  {
    variants: {
      orientation: {
        horizontal:
          'w-px cursor-col-resize after:absolute after:inset-y-0 after:left-1/2 after:w-1 after:-translate-x-1/2',
        vertical:
          'h-px w-full cursor-row-resize after:absolute after:inset-x-0 after:top-1/2 after:h-1 after:-translate-y-1/2',
      },
      disabled: { true: 'cursor-default opacity-50', false: '' },
    },
    defaultVariants: { orientation: 'horizontal', disabled: false },
  },
);

export const resizableGripVariants = cva(
  'z-10 flex items-center justify-center rounded-xs border bg-border text-muted-foreground [&_ng-icon]:text-[0.625rem]',
  {
    variants: {
      orientation: { horizontal: 'h-4 w-3', vertical: 'h-3 w-4 [&_ng-icon]:rotate-90' },
    },
    defaultVariants: { orientation: 'horizontal' },
  },
);

export const resizablePanelVariants = cva('relative overflow-hidden');

export type HbResizableOrientation = NonNullable<
  VariantProps<typeof resizableGroupVariants>['orientation']
>;
